# SLA breach alert: check p99 latency and fire PagerDuty
import requests
from datetime import datetime, timezone

PAGERDUTY_ROUTING_KEY = "..."
GRAFANA_API = "https://grafana.internal/api/ds/query"

def check_latency_sla(tier: str = "tier_1", threshold_ms: int = 3000) -> None:
    """Query Grafana for p99 latency and alert if SLA is breached."""
    resp = requests.post(GRAFANA_API, json={
        "queries": [{
            "refId": "A",
            "expr": 'histogram_quantile(0.99, rate(platform_api_duration_bucket[5m]))',
        }],
        "from": "now-5m",
        "to": "now",
    }, headers={"Authorization": "Bearer ..."})

    p99_ms = resp.json()["results"]["A"]["frames"][0]["data"]["values"][1][-1] * 1000

    if p99_ms > threshold_ms:
        trigger_pagerduty(
            summary=f"[{tier.upper()}] Platform API p99 latency {p99_ms:.0f}ms exceeds SLA {threshold_ms}ms",
            severity="critical" if tier == "tier_1" else "warning",
        )
